from agent import *from models.products import *import simplejsonimport reXCAT = ['Blogs', 'Recipes', 'All Stand Mixers', 'Air Fryer Campaign', 'Attachment Compatibility Charts', 'Home', 'Bargain Bin', 'Shop by Product Collection', 'Spares & Repairs', 'Attachment Compatibility Chart', 'All Stand Mixers', 'Product Support']def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://shopkenwood.co.za/', use='curl'), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//nav[@aria-label="Primary"]/ul[contains(@class, "main-nav")]/li')    for cat in cats:        name = cat.xpath('div/a/text()').string()        if name not in XCAT:            subcats = cat.xpath('.//ul/li[not(@class)]/a')            for subcat in subcats:                subcat_name = subcat.xpath('text()').string().replace('Other', '').strip()                url = subcat.xpath('@href').string()                if subcat_name not in XCAT and 'All ' not in subcat_name:                    session.queue(Request(url, use='curl'), process_prodlist, dict(cat=name+'|'+subcat_name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[contains(@class, "card__info-inner")]')    for prod in prods:        name = prod.xpath('.//a[contains(@class, "card-link")]/text()').string()        url = prod.xpath('.//a[contains(@class, "card-link")]/@href').string()        revs_cnt = prod.xpath('.//div[contains(@class, "rating__count")]/text()').string()        if revs_cnt and 'no' not in revs_cnt.lower():            if revs_cnt > 0:                session.queue(Request(url, use='curl'), process_product, dict(context, name=name, url=url))    # No next urldef process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = data.xpath('//input[@name="product-id"]/@value').string()    product.sku = product.ssid    product.category = context['cat']    product.manufacturer = 'Kenwood'    prod_json = data.xpath('''//script[contains(., '"@type":"Product"')]/text()''').string()    if prod_json:        prod_json = simplejson.loads(prod_json)        mpn = prod_json.get('sku')        if mpn:            product.add_property(type='id.manufacturer', value=mpn)        ean = prod_json.get('gtin')        if ean and str(ean).isdigit() and len(str(ean)) > 10:            product.add_property(type='id.ean', value=ean)    if product.ssid:        revs_url = 'https://judge.me/reviews/reviews_for_widget?url=kenwood-south-africa.myshopify.com&shop_domain=kenwood-south-africa.myshopify.com&platform=shopify&per_page=5&product_id={}'.format(product.ssid)        session.do(Request(revs_url, max_age=0), process_reviews, dict(product=product))def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    revs_json = simplejson.loads(data.content)    revs = revs_json.get('reviews', [])    for rev in revs:        review = Review()        review.url = product.url        review.type = 'user'        review.ssid = rev.get('uuid')        date = rev.get('created_at')        if date:            review.date = date.split('T')[0]        author = rev.get('reviewer_name')        if author:            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.get('rating')        if grade_overall and float(grade_overall) > 0:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        is_verified = rev.get('verified_buyer')        if is_verified is True:            review.add_property(type='is_verified_buyer', value=is_verified)        hlp_yes = rev.get('thumb_up')        if hlp_yes and int(hlp_yes) > 0:            review.add_property(type='helpful_votes', value=int(hlp_yes))        hlp_no = rev.get('thumb_down')        if hlp_no and int(hlp_no) > 0:            review.add_property(type='not_helpful_votes', value=int(hlp_no))        title = rev.get('title')        excerpt_html = rev.get('body_html')        excerpt = data.parse_fragment(excerpt_html).xpath('.//text()').string(multiple=True)        if excerpt and len(remove_emoji(excerpt).replace('\n', '').replace('\r', '').strip()) > 2:            if title:                review.title = remove_emoji(title).strip()        else:            excerpt = title        if excerpt:            excerpt = remove_emoji(excerpt).replace('\n', '').replace('\r', '').strip()            if len(excerpt) > 2:                review.add_property(type='excerpt', value=excerpt)                product.reviews.append(review)    page_cnt = context.get('page_cnt', revs_json.get('pagination', {}).get('total_pages'))    next_page = context.get("page", 1) + 1    if next_page <= page_cnt:        revs_url = 'https://judge.me/reviews/reviews_for_widget?url=kenwood-south-africa.myshopify.com&shop_domain=kenwood-south-africa.myshopify.com&platform=shopify&page=' + str(next_page) + '&per_page=5&product_id=' + product.ssid        session.do(Request(revs_url, max_age=0), process_reviews, dict(product=product, page=next_page, page_cnt=page_cnt))    elif product.reviews:        session.emit(product)